221	/// Permanent sanity check for the `main`-bookmark tracking state
222	/// in both repos of the dual-repo workspace. Prints one line on
223	/// entry and one on exit of every command. If entry and exit
224	/// differ, the executing command is the culprit; if entry differs
225	/// from the previous command's exit, something *between*
226	/// invocations broke it. Originally added in 0.37.2 as a temporary
227	/// diagnostic; promoted to permanent in 0.37.4 after the user
228	/// reported "happens more than once" — the signal is worth keeping
229	/// in place until confidence in its correctness is well-established
230	/// across varied use, at which point a "silent when clean"
231	/// refinement would remove the steady-state noise without losing
232	/// detection value (see `notes/todo.md`).
233	///
234	/// Walks up from cwd to locate the workspace root (the directory
235	/// whose `.vc-config.toml` has `path = "/"`), then probes `<root>`
236	/// and `<root>/.claude`. Same labeling whether the user runs from
237	/// the app root, from `.claude`, or from any subdir.
238	fn bm_track(phase: &str, command_name: &str) {
239	    let header = format!("bm-track {phase} vc-x1 {command_name}");
240	    let root = match find_workspace_root() {
241	        Some(r) => r,
242	        None => {
243	            log::info!("{header}: no-workspace");
244	            return;
245	        }
246	    };
247	    let repos: [(std::path::PathBuf, &str); 2] =
248	        [(root.clone(), "app"), (root.join(".claude"), ".claude")];
249	    let mut parts: Vec<String> = Vec::new();
250	    for (repo, label) in repos {
251	        if !repo.join(".jj").exists() {
252	            parts.push(format!("{label}(main)=no-jj"));
253	            continue;
254	        }
255	        match bm_track_one(&repo, "main", "origin") {
256	            Ok(true) => parts.push(format!("{label}(main)=tracked")),
257	            Ok(false) => parts.push(format!("{label}(main)=NOT_TRACKED")),
258	            Err(e) => parts.push(format!(
259	                "{label}(main)=err({})",
260	                e.lines().next().unwrap_or("")
261	            )),
262	        }
263	    }
264	    log::info!("{header}: {}", parts.join(", "));
265	}
266	
267	/// Walk up from cwd looking for `.vc-config.toml` with `path = "/"`.
268	/// That's the workspace root — the app-repo side of the dual-repo
269	/// pair. Returns `None` if no such config is found up to filesystem
270	/// root (e.g., running from outside any vc-x1 workspace).
271	fn find_workspace_root() -> Option<std::path::PathBuf> {
272	    let mut cur = std::env::current_dir().ok()?;
273	    loop {
274	        let config = cur.join(".vc-config.toml");
275	        if let Ok(content) = std::fs::read_to_string(&config) {
276	            // Match either `path = "/"` or `path="/"` (with/without spaces).
277	            let compact: String = content
278	                .lines()
279	                .find(|l| l.trim_start().starts_with("path"))
280	                .unwrap_or("") // OK: no `path =` line ⇒ empty match, continues walking up
281	                .chars()
282	                .filter(|c| !c.is_whitespace())
283	                .collect();
284	            if compact.starts_with("path=\"/\"") {
285	                return Some(cur);
286	            }
287	        }
288	        cur = cur.parent()?.to_path_buf();
289	    }
290	}
291	
292	/// Query jj for whether `bookmark` in `repo` is tracking `remote`.
293	/// Returns `Ok(true)` if the tracked-list entry for `bookmark` shows
294	/// an `@<remote>` line (in any form — `@origin:` when synced, or
295	/// `@origin (ahead by N commits):` / similar when divergent — both
296	/// still count as tracking). `Ok(false)` when no such line exists
297	/// (bookmark isn't tracking this remote or doesn't exist). `Err` on
298	/// subprocess failure.
299	fn bm_track_one(repo: &Path, bookmark: &str, remote: &str) -> Result<bool, String> {
300	    let repo_str = repo.to_string_lossy();
301	    let output = std::process::Command::new("jj")
302	        .args(["bookmark", "list", "--tracked", bookmark, "-R", &repo_str])
303	        .output()
304	        .map_err(|e| format!("spawn: {e}"))?;
305	    if !output.status.success() {
306	        return Err(String::from_utf8_lossy(&output.stderr).trim().to_string());
307	    }
308	    let stdout = String::from_utf8_lossy(&output.stdout);
309	    // Accept both the synced form (`@origin:`) and the decorated
310	    // divergent form (`@origin (ahead by N commits):`), which still
311	    // represents a tracking relationship.
312	    let colon = format!("@{remote}:");
313	    let paren = format!("@{remote} ");
314	    Ok(stdout.lines().any(|l| {
315	        let t = l.trim_start();
316	        t.starts_with(&colon) || t.starts_with(&paren)
317	    }))
318	}
319	
320	fn main() -> ExitCode {
321	    CompleteEnv::with_factory(cli_with_banner).complete();
322	    let matches = cli_with_banner().get_matches();
323	    let cli = match Cli::from_arg_matches(&matches) {
324	        Ok(cli) => cli,
325	        Err(e) => {
326	            e.exit();
327	        }
328	    };
329	
330	    let log_path = cli.log.as_ref().map(|p| p.to_string_lossy().to_string());
331	    logging::CliLogger::init(cli.verbose, log_path.as_deref());
332	
333	    // The detached `finalize --exec` re-entry is the bot's
334	    // session-end child; it shouldn't print the banner (extra
335	    // chatter in its log) or surface user-facing failure markers
336	    // (those are meant for the user's next interactive run).
337	    let is_detached_exec = matches!(
338	        cli.command,
339	        Commands::Finalize(ref f) if f.exec
340	    );
341	
342	    // `-L` / `--no-label` on the read-only multi-repo subcommands
343	    // (chid, desc, list, show) makes their output script-parseable
344	    // — adding a leading `vc-x1 X.Y.Z` line would break that. Skip
345	    // the banner whenever the active subcommand has the flag set.
346	    let suppress_banner = match &cli.command {
347	        Commands::Chid(a) => a.common.no_label,
348	        Commands::Desc(a) => a.common.no_label,
349	        Commands::List(a) => a.common.no_label,
350	        Commands::Show(a) => a.common.no_label,
351	        _ => false,
352	    };
353	
354	    if !is_detached_exec {
355	        if !suppress_banner {
356	            // Banner on every normal run, mirroring what `--help`
357	            // shows at the top.
358	            log::info!("{BANNER}");
359	        }
360	        finalize::surface_previous_failures();
361	    }
362	
363	    // Command name for bm-track output (first positional arg after
364	    // the binary; clap has already validated it by the time we get here).
365	    let command_name = std::env::args().nth(1).unwrap_or_else(|| "?".to_string()); // OK: default when somehow invoked without a subcommand
366	
367	    if !is_detached_exec {
368	        bm_track("enter", &command_name);
369	    }
370	
371	    let exit_code = match cli.command {
372	        Commands::Chid(chid_args) => run_command(chid::chid(&chid_args)),
373	        Commands::Desc(desc_args) => run_command(desc::desc(&desc_args)),
374	        Commands::List(list_args) => run_command(list::list(&list_args)),
375	        Commands::Show(show_args) => run_command(show::show(&show_args)),
376	        Commands::ValidateDesc(validate_desc_args) => {
377	            run_command(validate_desc::validate_desc(&validate_desc_args))
378	        }
379	        Commands::FixDesc(fix_desc_args) => run_command(fix_desc::fix_desc(&fix_desc_args)),
380	        Commands::Clone(clone_args) => run_command(clone::clone_repo(&clone_args)),
381	        Commands::Init(init_args) => run_command(init::init(&init_args)),
382	        Commands::Symlink(symlink_args) => run_command(symlink::symlink(&symlink_args)),
383	        Commands::Sync(sync_args) => run_command(sync::sync(&sync_args)),
384	        Commands::Finalize(finalize_args) => {
385	            let opts = match finalize_args.into_opts(cli.log) {
386	                Ok(opts) => opts,
387	                Err(e) => {
388	                    error!("{e}");
389	                    return ExitCode::FAILURE;
390	                }
391	            };
392	            run_command(finalize::finalize(&opts))
393	        }
394	        Commands::TestFixture(args) => run_command(test_fixture::test_fixture(&args)),
395	        Commands::TestFixtureRm(args) => run_command(test_fixture::test_fixture_rm(&args)),
396	        Commands::Push(push_args) => run_command(push::push(&push_args)),
397	    };
398	
399	    if !is_detached_exec {
400	        bm_track("exit ", &command_name);
401	    }
402	
403	    exit_code
404	}
