426	/// Header style between repos in multi-repo output.
427	#[derive(Debug, Clone)]
428	pub enum Header {
429	    /// Show `deco path deco` header per repo.
430	    Label(String),
431	    /// No header at all.
432	    None,
433	}
434	
435	/// Resolve `-l` / `-L` flags into a `Header`.
436	///
437	/// `-L` (no header) takes precedence over `-l` (label decoration).
438	pub fn resolve_header(label: &str, suppress: bool) -> Header {
439	    if suppress {
440	        Header::None
441	    } else {
442	        Header::Label(label.to_string())
443	    }
444	}
445	
446	/// Expand comma-separated repo paths, default to `["."]`, and run a closure for each.
447	///
448	/// Header style controls output between repos.
449	/// Continues past errors, printing them to stderr, and returns an error if any failed.
450	pub fn for_each_repo<F>(
451	    raw_repos: &[PathBuf],
452	    header: &Header,
453	    mut body: F,
454	) -> Result<(), Box<dyn std::error::Error>>
455	where
456	    F: FnMut(&Workspace, &Arc<ReadonlyRepo>) -> Result<(), Box<dyn std::error::Error>>,
457	{
458	    let repos: Vec<PathBuf> = if raw_repos.is_empty() {
459	        vec![PathBuf::from(".")]
460	    } else {
461	        raw_repos
462	            .iter()
463	            .flat_map(|p| {
464	                p.to_string_lossy()
465	                    .split(',')
466	                    .map(|s| PathBuf::from(s.trim()))
467	                    .collect::<Vec<_>>()
468	            })
469	            .collect()
470	    };
471	    let multi = repos.len() > 1;
472	    let mut first = true;
473	    let mut errors: Vec<String> = Vec::new();
474	
475	    for repo_path in &repos {
476	        if multi {
477	            match header {
478	                Header::Label(deco) => {
479	                    if !first {
480	                        info!("");
481	                    }
482	                    info!(
483	                        "{}",
484	                        bold(&format!("{deco} {} {deco}", repo_path.display()))
485	                    );
486	                }
487	                Header::None => {}
488	            }
489	        }
490	        first = false;
491	
492	        match load_repo(repo_path) {
493	            Ok((workspace, repo)) => {
494	                if let Err(e) = body(&workspace, &repo) {
495	                    error!("({}): {e}", repo_path.display());
496	                    errors.push(format!("{}: {e}", repo_path.display()));
497	                }
498	            }
499	            Err(e) => {
500	                error!("({}): {e}", repo_path.display());
501	                errors.push(format!("{}: {e}", repo_path.display()));
502	            }
503	        }
504	    }
505	
506	    if errors.is_empty() {
507	        Ok(())
508	    } else {
509	        Err(format!("{} repo(s) had errors", errors.len()).into())
510	    }
511	}
512	
513	pub fn load_repo(
514	    path: &Path,
515	) -> Result<(Workspace, Arc<ReadonlyRepo>), Box<dyn std::error::Error>> {
516	    let config = StackedConfig::with_defaults();
517	    let settings = UserSettings::from_config(config)?;
518	    let store_factories = StoreFactories::default();
519	    let working_copy_factories = default_working_copy_factories();
520	
521	    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
522	    let repo = workspace.repo_loader().load_at_head().block_on()?;
523	
524	    Ok((workspace, repo))
525	}
